import lombok.extern.java.Log
import lombok.AccessLevel
import lombok.NoArgsConstructor

@Log(access = AccessLevel.PUBLIC)
@NoArgsConstructor(staticName = "make", force = true)
class Klass(val a: Int, val b: String)

@NoArgsConstructor(staticName = "make", force = true)
@Log(access = AccessLevel.PUBLIC)
class Klass2(val a: Int, val b: String)

fun box(): String {
    Klass.log.info("Check `Klass.Companion.log`")

    // Check that `make` also lives in the companion object generated by logger generator
    val klass = Klass.make()
    assertEquals(0, klass.a)
    assertEquals(null, klass.b)

    // Check that `log` also lives in the companion object generated by constructors generator
    Klass2.log.info("Check `Klass2.Companion.log`")

    val klass2 = Klass2.make()
    assertEquals(0, klass2.a)
    assertEquals(null, klass2.b)

    return "OK"
}
